1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest quote cases (base premiums + processing fee) ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("single plain sword, newcomer first quote → 100 base + 10 first = 110 + 5 fee = 115 G", () => {
14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
20	        },
21	      ],
22	    });
23	    expect(result).toEqual({ results: [{ premium: 115 }] });
24	  });
25	  it.todo("single amulet → 60 base + 5 fee = 65 G");
26	  it.todo("single staff → 80 base + 5 fee = 85 G");
27	  it.todo("single potion → 40 base + 5 fee = 45 G");
28	  it.todo("single rune (component) → 25 base + 5 fee = 30 G");
29	  it.todo("single moonstone (component) → 25 base + 5 fee = 30 G");
30	
31	  // --- Building block of 3 alike components ---
32	  it.todo("2 runes → 50 G base premium (no block)");
33	  it.todo("3 runes → 60 G base premium (block applies)");
34	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
35	  it.todo("7 runes → 175 G base premium (no block beyond 3)");
36	
37	  // --- Alike components clarification ---
38	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
39	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
40	
41	  // --- Item-specific modifiers ---
42	  it.todo("cursed sword adds 50% surcharge to item base premium");
43	  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
44	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
45	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
46	
47	  // --- Policy-wide modifiers ---
48	  it.todo("customer with exactly 2 years → loyalty discount applies (20%)");
49	  it.todo("customer with 0 years → no loyalty discount");
50	  it.todo("first quote of a customer → 10% first insurance surcharge applies");
51	  it.todo("second quote of a customer → 15% follow-up contract discount applies");
52	
53	  // --- Modifier scope on multi-item policies ---
54	  it.todo("cursed sword + plain amulet → policy base 160 G, +50 G curse, +5 fee = 215 G");
55	
56	  // --- Rounding in MHPCO's favor (premium rounds up) ---
57	  it.todo("premium that yields 197.5 G → 198 G (rounded up)");
58	
59	  // --- Integration examples from spec ---
60	  it.todo("newcomer with cursed sword (steel, ench 3), 0 yrs → premium 165 G");
61	  it.todo("long-standing customer's 2nd contract, cursed sword ench 7 → premium 160 G");
62	
63	  // --- Claim processing: basic deductible and reimbursement ---
64	  it.todo("regular sword (steel ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
65	  it.todo("rune damage 200 G → payout 100 G (no special clause, − deductible)");
66	
67	  // --- Dragon material clause ---
68	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full − deductible)");
69	
70	  // --- High-enchantment clause (>= 8) ---
71	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% − deductible)");
72	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, − deductible)");
73	  it.todo("dragon-material sword, ench exactly 8, damage 1000 G → payout 400 G (50% applies, − deductible)");
74	
75	  // --- Deductible per damage event (per damaged item) ---
76	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
77	
78	  // --- Multiple items of same type ---
79	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G; both damaged → two deductibles");
80	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero");
81	
82	  // --- Cap exhaustion ---
83	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
84	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
85	  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
86	  it.todo("two successive 1500 G claims on sword (cap 2000): payouts 1400, 600; remainingCap 600, 0");
87	
88	  // --- Rounding of payout (rounds down — MHPCO's favor) ---
89	  it.todo("payout that yields 350.5 G → 350 G (rounded down)");
90	
91	  // --- Edge cases ---
92	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
93	  it.todo("claim references damage item not in policy → CLI exits non-zero, error to stderr");
94	  it.todo("claim damage with negative amount → CLI exits non-zero, error to stderr");
95	});
