1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Step = QuoteStep;
4	type Customer = { yearsWithMHPCO: number };
5	type Scenario = { customer: Customer; steps: Step[] };
6	type QuoteResult = { premium: number };
7	type Result = QuoteResult;
8	
9	const PROCESSING_FEE = 5;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	};
14	
15	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
16	
17	const quotePremium = (items: Item[]): number => {
18	  if (items.length === 0) return PROCESSING_FEE;
19	  const policyBase = items.reduce((sum, i) => sum + itemBasePremium(i), 0);
20	  const withFirstInsurance = (policyBase * 110) / 100;
21	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
22	};
23	
24	export const runScenario = (scenario: Scenario): { results: Result[] } => {
25	  const results: Result[] = scenario.steps.map((step) => ({
26	    premium: quotePremium(step.items),
27	  }));
28	  return { results };
29	};
